export const lpic2_quiz_pool = [
  // Topic 200: Capacity Planning
  { id: 'lpic2-200-1', topicId: 1, question: '¿Qué comando proporciona una vista dinámica y en tiempo real del sistema y los procesos en ejecución, destacando el uso de CPU y memoria?', options: ['free', 'top', 'uptime', 'vmstat'], answer: 1, explanation: 'El comando `top` proporciona una vista en tiempo real de los procesos en ejecución.' },
  { id: 'lpic2-200-2', topicId: 1, question: '¿Cuál de los siguientes comandos usarías para ver estadísticas detalladas de I/O para dispositivos de bloques?', options: ['vmstat', 'iostat', 'netstat', 'mpstat'], answer: 1, explanation: 'El comando `iostat` se usa para monitorizar la carga de los dispositivos de entrada/salida del sistema.' },
  { id: 'lpic2-200-3', topicId: 1, question: 'Deseas recopilar y visualizar las tendencias de rendimiento del sistema durante varios meses. ¿Qué herramienta es la más adecuada para esto?', options: ['top', 'ss', 'Collectd/MRTG/Cacti', 'tcpdump'], answer: 2, explanation: 'Collectd, MRTG y Cacti son herramientas estándar diseñadas para recopilar datos a lo largo del tiempo y generar gráficos para la planificación de capacidad.' },
  { id: 'lpic2-200-4', topicId: 1, question: '¿Qué herramienta puedes usar para predecir futuras necesidades de capacidad basándote en tendencias actuales?', options: ['mrtg', 'ping', 'fsck', 'ls'], answer: 0, explanation: 'MRTG (Multi Router Traffic Grapher) se usa para monitorear el tráfico y la capacidad a lo largo del tiempo.' },
  { id: 'lpic2-200-5', topicId: 1, question: '¿Qué hace el comando `sar`?', options: ['Busca archivos', 'System Activity Reporter (Informa sobre la actividad del sistema)', 'Guarda archivos', 'Detiene todos los procesos en ejecución'], answer: 1, explanation: 'sar (System Activity Reporter) se usa para recopilar, reportar o guardar información de actividad del sistema.' },

  // Topic 201: Linux Kernel
  { id: 'lpic2-201-1', topicId: 2, question: '¿Dónde residen en el sistema de archivos los módulos del kernel compilados por defecto?', options: ['/boot/modules/', '/lib/modules/$(uname -r)/', '/etc/kernel/', '/var/lib/modules/'], answer: 1, explanation: 'Los módulos del kernel se almacenan en `/lib/modules/` bajo un directorio que coincide con la versión específica del kernel.' },
  { id: 'lpic2-201-2', topicId: 2, question: '¿Qué objetivo (target) de make se utiliza para construir una imagen de kernel comprimida en los kernels modernos (2.6+)?', options: ['make zImage', 'make bzImage', 'make vmlinux', 'make install'], answer: 1, explanation: '`make bzImage` crea una imagen de kernel comprimida (big zImage) que maneja los kernels que superan las antiguas limitaciones de tamaño de zImage.' },
  { id: 'lpic2-201-3', topicId: 2, question: 'Al configurar el kernel desde el código fuente, ¿qué comando proporciona una interfaz de texto basada en menús?', options: ['make config', 'make menuconfig', 'make xconfig', 'make defconfig'], answer: 1, explanation: '`make menuconfig` requiere ncurses y proporciona una interfaz de menú basada en texto para configurar el kernel.' },
  { id: 'lpic2-201-4', topicId: 2, question: '¿Qué herramienta se usa para cargar un módulo del kernel junto con sus dependencias?', options: ['insmod', 'modinfo', 'modprobe', 'rmmod'], answer: 2, explanation: 'modprobe añade o elimina módulos del kernel de forma inteligente, resolviendo las dependencias automáticamente.' },
  { id: 'lpic2-201-5', topicId: 2, question: '¿Qué archivo contiene los símbolos del kernel necesarios para la depuración?', options: ['vmlinux', 'System.map', 'bzImage', 'initrd'], answer: 1, explanation: 'System.map actúa como una tabla de símbolos, mapeando los nombres de los símbolos del kernel a sus direcciones en memoria.' },

  // Topic 202: System Startup
  { id: 'lpic2-202-1', topicId: 3, question: 'En un sistema SysVinit tradicional, ¿qué archivo dicta el nivel de ejecución (runlevel) por defecto al arrancar?', options: ['/etc/inittab', '/etc/runlevel', '/boot/grub/grub.cfg', '/etc/init.d/rcS'], answer: 0, explanation: 'El archivo `/etc/inittab` configura el proceso init y establece el runlevel predeterminado (initdefault).' },
  { id: 'lpic2-202-2', topicId: 3, question: '¿Qué comando actualiza el archivo de configuración de GRUB 2 en sistemas basados en Debian?', options: ['grub-install', 'grub2-mkconfig', 'update-grub', 'grub-setup'], answer: 2, explanation: '`update-grub` es un script en Debian/Ubuntu que engloba el comando grub-mkconfig.' },
  { id: 'lpic2-202-3', topicId: 3, question: 'Durante una recuperación del sistema, necesitas arrancar en modo mono-usuario en systemd. ¿Qué target se utiliza?', options: ['runlevel1.target', 'rescue.target', 'single.target', 'emergency.target'], answer: 1, explanation: '`rescue.target` es el equivalente en systemd al modo mono-usuario.' },
  { id: 'lpic2-202-4', topicId: 3, question: '¿Dónde se ubica típicamente el archivo de configuración principal de GRUB 2?', options: ['/boot/grub/grub.conf', '/boot/grub2/grub2.cfg', '/boot/grub/grub.cfg', '/etc/grub.cfg'], answer: 2, explanation: 'El archivo de configuración principal generado para GRUB 2 es típicamente `/boot/grub/grub.cfg`.' },
  { id: 'lpic2-202-5', topicId: 3, question: '¿Qué parámetro puedes añadir a la línea de comandos del kernel en GRUB para saltarte el sistema init y abrir una consola root?', options: ['init=/bin/sh', 'single', 'rescue', 'bash'], answer: 0, explanation: 'Añadir `init=/bin/sh` hace que el kernel monte el sistema de archivos raíz en modo sólo-lectura y abra una terminal (shell) en lugar de lanzar systemd o SysVinit.' },

  // Topic 203: Filesystem and Devices
  { id: 'lpic2-203-1', topicId: 4, question: '¿Qué tipo de sistema de archivos depende en gran medida de los "extents" y es el predeterminado para muchas distribuciones modernas basadas en RHEL?', options: ['ext4', 'xfs', 'btrfs', 'zfs'], answer: 1, explanation: 'XFS es altamente escalable y el predeterminado en RHEL 7+ y derivados.' },
  { id: 'lpic2-203-2', topicId: 4, question: '¿Qué comando comprueba un sistema de archivos ext4 en busca de errores?', options: ['fsck.ext4', 'e2fsck', 'Tanto A como B', 'xfs_repair'], answer: 2, explanation: '`fsck.ext4` y `fsck.ext3` suelen ser un hardlink o envoltorio para `e2fsck`.' },
  { id: 'lpic2-203-3', topicId: 4, question: '¿Cuál es el propósito del archivo `/etc/fstab`?', options: ['Configurar el gestor de arranque', 'Listar los sistemas de archivos que deben montarse automáticamente al inicio', 'Almacenar contraseñas de usuario', 'Configurar interfaces de red'], answer: 1, explanation: 'fstab (file systems table) define las reglas sobre cómo y dónde montar particiones y discos al arrancar el sistema.' },
  { id: 'lpic2-203-4', topicId: 4, question: '¿Qué opción de smartctl muestra la evaluación general de salud de un disco duro?', options: ['-a', '-H', '-i', '-t short'], answer: 1, explanation: '`smartctl -H /dev/sda` muestra el estado de salud S.M.A.R.T. (PASSED o FAILED).' },
  { id: 'lpic2-203-5', topicId: 4, question: '¿Cómo creas una imagen ISO a partir de un dispositivo de bloque de CD-ROM (/dev/cdrom)?', options: ['tar -cvf image.iso /dev/cdrom', 'dd if=/dev/cdrom of=image.iso', 'mkisofs -o image.iso /dev/cdrom', 'cp /dev/cdrom image.iso'], answer: 1, explanation: '`dd` es la herramienta estándar para crear copias byte a byte de dispositivos de bloque.' },

  // Topic 204: Advanced Storage
  { id: 'lpic2-204-1', topicId: 5, question: '¿Qué herramienta se usa para montar y administrar arrays RAID por software en Linux?', options: ['lvm', 'fdisk', 'mdadm', 'parted'], answer: 2, explanation: '`mdadm` significa "multiple device admin" y es la utilidad estándar para el RAID por software.' },
  { id: 'lpic2-204-2', topicId: 5, question: '¿Qué nivel de RAID proporciona espejado (mirroring) sin división de datos (striping)?', options: ['RAID 0', 'RAID 1', 'RAID 5', 'RAID 10'], answer: 1, explanation: 'RAID 1 proporciona redundancia al clonar datos idénticamente en dos o más discos físicos.' },
  { id: 'lpic2-204-3', topicId: 5, question: 'En LVM, ¿qué comando se usa para añadir un nuevo disco duro físico inicializado a un Volume Group existente?', options: ['pvcreate', 'vgextend', 'lvextend', 'vgcreate'], answer: 1, explanation: '`vgextend groupname /dev/sdX` añade un volumen físico previamente creado al grupo.' },
  { id: 'lpic2-204-4', topicId: 5, question: '¿Qué flag de hdparm se usa para medir la velocidad de lectura pura de un disco duro sin utilizar la caché del búfer?', options: ['-T', '-S', '-t', '-y'], answer: 2, explanation: '`hdparm -t` realiza lecturas cronometradas del dispositivo (raw reads).' },
  { id: 'lpic2-204-5', topicId: 5, question: '¿Para qué se utiliza principalmente iSCSI?', options: ['Navegación segura por Internet', 'Transmitir comandos SCSI sobre redes IP', 'Un sustituto de NFS para compartir archivos', 'Cifrado local de hardware'], answer: 1, explanation: 'iSCSI encapsula el control y los datos SCSI para permitir el acceso al almacenamiento a nivel de bloque a través de redes IP (SANs).' },

  // Topic 205: Network Configuration
  { id: 'lpic2-205-1', topicId: 6, question: '¿Qué comando moderno del paquete iproute2 permite ver la caché ARP (tabla de vecinos)?', options: ['arp -n', 'ip neigh show', 'netstat -rn', 'route -n'], answer: 1, explanation: '`ip neigh show` (o simplemente `ip n`) reemplaza al antiguo comando `arp`.' },
  { id: 'lpic2-205-2', topicId: 6, question: '¿Qué comando muestra la tabla de enrutamiento actual usando la suite iproute2?', options: ['route', 'ip route show', 'netstat -r', 'ifconfig'], answer: 1, explanation: '`ip route show` o su versión corta `ip r` es el estándar en iproute2.' },
  { id: 'lpic2-205-3', topicId: 6, question: '¿Qué hace el comando `ping -c 4`?', options: ['Hace ping a 4 direcciones diferentes', 'Envía exactamente 4 paquetes ICMP de solicitud de eco (echo request)', 'Establece el tamaño del paquete a 4 bytes', 'Espera 4 segundos entre pings'], answer: 1, explanation: 'La opción `-c` significa "count" y limita el ping a exactamente 4 iteraciones de paquetes.' },
  { id: 'lpic2-205-4', topicId: 6, question: '¿Qué herramienta se considera el analizador de protocolos de red (sniffer de paquetes) estándar por línea de comandos en Linux?', options: ['wireshark', 'nmap', 'tcpdump', 'tracepath'], answer: 2, explanation: 'tcpdump captura y analiza el tráfico de red directamente en una interfaz desde el terminal.' },
  { id: 'lpic2-205-5', topicId: 6, question: '¿En qué puerto TCP opera típicamente HTTPS?', options: ['80', '21', '22', '443'], answer: 3, explanation: 'HTTPS (HTTP protegido por TLS/SSL) utiliza el puerto estándar 443.' },

  // Topic 206: System Maintenance
  { id: 'lpic2-206-1', topicId: 7, question: 'Al compilar un programa C desde el código fuente proporcionado en un "tarball", ¿qué orden de comandos es el estándar histórico?', options: ['make > make install > ./configure', './configure > make > make install', 'make install > ./configure > make', 'untar > make install > ./configure'], answer: 1, explanation: 'Primero ejecutas configure para generar los makefiles, luego make para compilar y make install para mover los binarios finales.' },
  { id: 'lpic2-206-2', topicId: 7, question: '¿Qué comando sincroniza achivos de forma eficiente copiando sólo los bloques modificados (deltas) mediante algoritmos rápidos?', options: ['cp', 'scp', 'ftp', 'rsync'], answer: 3, explanation: 'rsync es un utilitario para transferencia rápida y versátil que usa un famoso algoritmo de diferencias para minimizar el tráfico.' },
  { id: 'lpic2-206-3', topicId: 7, question: '¿Qué rastrea o depura el comando `strace`?', options: ['Busca vulnerabilidades en puertos', 'Rastrea las llamadas al sistema (system calls) y las señales enviadas o recibidas por un proceso', 'Optimiza los discos duros', 'Muestra variables de sistema'], answer: 1, explanation: 'strace intercepta y registra las llamadas a la API del kernel (system calls) ejecutadas por un determinado PID o aplicación.' },
  { id: 'lpic2-206-4', topicId: 7, question: '¿Qué herramienta lista detalladamente todos los archivos abiertos por procesos activos en el sistema?', options: ['lsof', 'ps', 'top', 'find'], answer: 0, explanation: '`lsof` significa "list open files". En Unix, casi todo (incluyendo sockets y de hardware) es tratado como un "archivo".' },
  { id: 'lpic2-206-5', topicId: 7, question: '¿Qué flags de `tar` se utilizan típicamente para extraer un archivo comprimido estándar con GZIP (.tar.gz)?', options: ['-cvf', '-xvf', '-zxvf', '-jcvf'], answer: 2, explanation: 'z es para decodificar Gzip, x para extaer (eXtract), v para verbosidad interactiva y f alinea el parametro FileName.' },

  // Topic 207: Domain Name Server
  { id: 'lpic2-207-1', topicId: 8, question: 'Dentro de un DNS BIND, ¿qué registro de zona tiene la función de apuntar un FQDN a un identificador IPv4?', options: ['MX', 'CNAME', 'A', 'AAAA'], answer: 2, explanation: 'El registro A (Address) define la IP directa (v4).' },
  { id: 'lpic2-207-2', topicId: 8, question: '¿Qué comando oficial de BIND analiza estructuralmente un archivo de zona de una nueva configuración para garantizar que no existan errores de sintaxis catastróficos al ricaricar?', options: ['named-checkconf', 'named-checkzone', 'dns-lint', 'dig'], answer: 1, explanation: 'Antes de aplicar los cambios en un zone-file, la utilidad `named-checkzone` evalúa la precisión de la zona.' },
  { id: 'lpic2-207-3', topicId: 8, question: '¿Para qué sirve instanciar un registro tipo MX?', options: ['Traducciones inversas', 'Anotación de los Mail Exchange responsables de recepcionar los correos de un dominio', 'Traducción Ipv6', 'Redirigir a otras sub-zonas completas'], answer: 1, explanation: 'Los registros Mail Exchange (MX) determinan a qué Servidor de Correos de internet será despachado el flujo SMTP dirigido a un dominio.' },
  { id: 'lpic2-207-4', topicId: 8, question: 'Para evitar secuestros como el DNS cache poisoning y el Spoofing, ¿qué extensión firma las consultas basándose en clave pública PGP?', options: ['DNS-Over-HTTPS (DoH)', 'TLS', 'DNSSEC', 'TSIG'], answer: 2, explanation: 'DNSSEC (Domain Name System Security Extensions) agrega seguridad criptográfica a los datos en las resoluciones de dominio DNS previniendo la adulteración de IPs entre name servers.' },
  { id: 'lpic2-207-5', topicId: 8, question: '¿Dónde se encuentra convencionalmente el registro de configuraciones que modera al Demonio BIND?', options: ['/etc/bind/bind.conf', '/etc/named.conf', '/var/named/config', '/etc/resolv.conf'], answer: 1, explanation: 'La directiva general o fichero madre global de Bind yace por defecto en `/etc/named.conf` (o en derivaciones /etc/bind/named.conf).' },

  // Topic 208: Web Services
  { id: 'lpic2-208-1', topicId: 9, question: 'En un servidor Web Apache, ¿qué bloque declara las particularidades y los prefijos de Servidor para habilitar múltiples sitios alojados en una sola máquina física/IP?', options: ['<Directory>', '<ServerHost>', '<VirtualHost>', '<Website>'], answer: 2, explanation: 'La etiqueta <VirtualHost> aísla y empaqueta las directivas, los dominios designados y los DocumentRoot individualmente.' },
  { id: 'lpic2-208-2', topicId: 9, question: 'El Daemon Nginx destaca en el mundo Enterprise principalmente porque funge de modo experto como...', options: ['Servidor Autoritativo de nombres DNS local', 'Proxy Inverso (Reverse Proxy) de alta resiliencia y Balanceador de cargas Web', 'Puro File Server con Active Directory', 'Motor Base de Datos estático'], answer: 1, explanation: 'Nginx saltó a la fama gracias a su ágil manipuleo multiproceso para derivar el tráfico entrante operando asíncronamente como Reverse Proxy, caché estática o balanceando varios nodos.' },
  { id: 'lpic2-208-3', topicId: 9, question: 'La aplicación Squid Proxy es mundialmente reconocida por su habilidad implementaria focalizada en qué rol?', options: ['SMTP Firewall', 'Proxy de Caché rápida para navegación web.', 'Base de Datos de log', 'Gestor Remoto Vnc'], answer: 1, explanation: 'Squid opera preferentemente interceptando o fungiendo de mediador TCP almacenando (Cache proxy) webs, HTTPS y peticiones afines acelerando el retorno de contenidos dentro de la empresa LAN y minimizando saturación WAN externa.' },
  { id: 'lpic2-208-4', topicId: 9, question: '¿Cuál es el Módulo fundamental e intrínseco en Apache necesario para gestionar encriptación y los certificados TLS?', options: ['mod_rewrite', 'mod_security', 'mod_ssl', 'mod_proxy'], answer: 2, explanation: 'El `mod_ssl` hace el puente criptográfico habilitando los protocolos HTTPS implementado librerías seguras de OpenSSL en Apache.' },
  { id: 'lpic2-208-5', topicId: 9, question: '¿Por cual puerto estándar de conectividad escucha generalmente un servidor Squid de serie?', options: ['80', '443', '3128', '8080'], answer: 2, explanation: 'Bajo la configuración general vainilla, Squid levantará su listener socket TCP por el 3128.' },

  // Topic 209: File Sharing
  { id: 'lpic2-209-1', topicId: 10, question: 'La capa imprescindible en redes para entrelazar recursos visuales, shares y printers nativos de ambiente Windows (SMB/CIFS) con nuestro Linux host se rige con:', options: ['NFS', 'Samba', 'FTP', 'SSHFS'], answer: 1, explanation: 'La suite Samba implementa sobre sistemas Unix e integrables el estándar privativo Netbios y CIFS facilitando la total compatibilidad Windows Active Directory o WorkGroup simple.' },
  { id: 'lpic2-209-2', topicId: 10, question: '¿Cual es el hogar del fichero madre "smb.conf" de Samba?', options: ['/etc/smb/smb.conf', '/etc/samba/smb.conf', '/usr/local/samba.cfg', '/var/lib/samba/config'], answer: 1, explanation: 'El epicentro es `/etc/samba/smb.conf`.' },
  { id: 'lpic2-209-3', topicId: 10, question: 'Hablando del servicio Kernel nativo rpc de NFS.. ¿Mediante que archivo determinamos y enunciamos a que segmento Cliente concedemos qué carpetas del Host Linux?', options: ['/etc/exports', '/etc/nfs.conf', '/etc/fstab', '/etc/samba/smb.conf'], answer: 0, explanation: 'Adentro del texto de `/etc/exports` się dictan las rutas y las Network Subnets a las cuales son esposte.' },
  { id: 'lpic2-209-4', topicId: 10, question: 'Una vez toqueteado una sintaxis en `/etc/exports`, ¿como aplicamos los filtros al volo sin staccare i Clients correnti in NFS?', options: ['nfs-update', 'systemctl reload nfs', 'exportfs -a / -r', 'mount -a'], answer: 2, explanation: 'El utilitario `exportfs -r` efectúa re-parse global y refresca la live-session di un NFS in esecuzione invisibilmente a los usuários.' },
  { id: 'lpic2-209-5', topicId: 10, question: 'Los Privilegios Auténticos sobre Samba son aislados de los usuarios crudos Linux shadow. ¿Qual es la función para insertar una password remota Samba a tu User Linux?', options: ['smbpasswd -a', 'useradd', 'passwd', 'pdbedit -n'], answer: 0, explanation: 'Mediante `smbpasswd -a {user}` el Host anota y crea entrada CIFS local Samba cifrando la contraseña para red Microsoft y mapeándola.' },

  // Topic 210: Network Client Management
  { id: 'lpic2-210-1', topicId: 11, question: 'Para centralizar todo el "leasing" e hidratación de un rango de direcciones IPv4 hacia los PCs que conectan en router, el estándar definitivo del protocolo IP dinámico se llama:', options: ['DNS', 'DHCP', 'ARP', 'ICMP'], answer: 1, explanation: 'Dynamic Host Configuration Protocol otorga en préstamo la configuración (IP/Submask/GW/DNS) por tiempos de Leases (arrendamientos).' },
  { id: 'lpic2-210-2', topicId: 11, question: 'Las Arquitecturas modernas incorporaron el ecosistema PAM, resolviendo el caos logístico de...', options: ['Administración modular global para delegar los métodos Autenticativos desde los Binarios de App hacía una serie de librerías estandarizadas en común e independientes.', 'Monitorizar los Paquetes Web IPtables', 'Firmar módulos en UEFI BIOS', 'Configurar discos remotos Nfs'], answer: 0, explanation: 'Pluggable Authentication Modules permite flexibilizar las formas de Autenticación de las Apps UNIX sin requerirles re-codificación ad hoc (por ej, conmutar SSH local a LDAP, SecurID, Multi-factor..).' },
  { id: 'lpic2-210-3', topicId: 11, question: '¿Cuál de los siguientes identifica la principal fortaleza por la que LDAP perdura como el corazón organizacional?', options: ['Linux Directory Authentication Protocol', 'Lightweight Directory Access Protocol', 'Local Domain Access Process', 'Large Data Authentication Platform'], answer: 1, explanation: 'El Protocolo Ligero Acceso a Directorios aloja listas maestras institucionales eficientes en Queries rápidas como "PhoneBooks", OrgCharts o Centralización de Identity Managers.' },
  { id: 'lpic2-210-4', topicId: 11, question: 'La arquitectura Kernel Net de OpenVPN brinda virtualización mediante TAP/TUN. Entrando con un adapter VPN "TUN", ¿en qué capa ISO nos insertamos limitados?', options: ['Capa Ethernet/MAC level 2 (Bridge Puro)', 'Capa IP de Ruteamiento - Network OSI Layer 3', 'Modo Bridge Criptografico promiscuo MAC address puro', 'A Nivel Criptográfico SSL Layer 5'], answer: 1, explanation: 'Un tun device rutea solo cabeceras IP puros (capa de red layer 3), filtrando el overhead Broadcast ARP/Mac Adressing.' },
  { id: 'lpic2-210-5', topicId: 11, question: 'Bajo que protocolo y en qué Port Address se consolida prioritariamente la escucha y binding principal de OpenVPn out-of-box?', options: ['1194 UDP', '22 TCP', '443 TCP', '53 UDP'], answer: 0, explanation: 'OpenVpn se decanta de serie oficializada IANA por UDP(User Datagram) en la toma 1194, eludiendo latencias de handshake TCP over TCP con paquetes robustos adaptables.' },

  // Topic 211: E-Mail Services
  { id: 'lpic2-211-1', topicId: 12, question: 'Los servicios pilares que despachan, conversan inter-nodo de Servidor Mails (MTA\'s tipo Exim o Postfix) se adhieren obligatoriamente a la convención IETF conocida con la sigla...', options: ['POP3', 'IMAP', 'SMTP', 'SNMP'], answer: 2, explanation: 'La ruta primigenia de comunicación es SMTP (Simple Mail Transfer Protocol).' },
  { id: 'lpic2-211-2', topicId: 12, question: 'Si hablamos del demonio MTA Postfix.. ¿El archivo principal que condensa el cerebro estático y la política operativa general del mail-server se denomina?', options: ['/etc/postfix/master.cf', '/etc/postfix/main.cf', '/etc/mail/sendmail.cf', '/var/spool/postfix/config'], answer: 1, explanation: 'Toda configuración o tunning global en Postfix corre por cuenta y modifica del gran `main.cf`.' },
  { id: 'lpic2-211-3', topicId: 12, question: 'Dejando la fase MTA, cual aplicación Daemon reina hoy sobre Linux para ofrecer Recuperación y Sincronía asíncrona de las bandejas E-mail mediante Protocolos IMAP y POP para clientes web/movil?', options: ['Postfix', 'Dovecot', 'Procmail', 'SpamAssassin'], answer: 1, explanation: 'Dovecot es, en inmensa hegemonía frente al viejo Courier, el Server MDA Pop/Imap de confianza estándar.' },
  { id: 'lpic2-211-4', topicId: 12, question: 'Entidades como "Procmail" o el lenguaje "Sieve Server Scripts" de Delivery Agent son herramientas que aportan un valor incalculable de cara a?', options: ['Entablar conexiones al host MX receptor.', 'Entregar y acomodar el File físico de un mensaje, posibilitando clasificar, reenviar y depositar inboxes aplicando potentes condicionales Lógicos y filtros Regex AntiSpam locales.', 'Sincronizar el Password LDAP con la cuenta MailBox.', 'Acelerar la Carga en RAM del servidor smtp.'], answer: 1, explanation: 'Son potentes Agentes de Entrega Locales. Cuando Postfix les inyecta un mail, revisan y tamizan aplicando las Reglas de "Bandeja Spam, auto-respuestas o filtrado Folder" antes de sellarlo en el formato fisico Mbox.' },
  { id: 'lpic2-211-5', topicId: 12, question: 'A modo histórico y persistente para emular sendmail: Luego de registrar "webmaster: alvaro" en `/etc/aliases`, ¡que compilador se emite en Bash shell per empujar un reload local indexato ad Hash Map del MTA?', options: ['makemap', 'newaliases', 'postmap', 'systemctl reload postfix'], answer: 1, explanation: 'El rehash lo emite instintivamente al vuelo la herramienta hereditaria `newaliases` produciendo el alias.db de consulta rápida para el daemon postfix.' },

  // Topic 212: System Security
  { id: 'lpic2-212-1', topicId: 13, question: 'Si estuviésemos auditando o tecleando la CLI prehistórica pero persistente Netfilter Iptables.. ¿En Cuál TABLE especial es lícito operar reglas exclusivas encargadas de reescribir y mimetizar la IP Origen (Masquerade_SNAT)?', options: ['filter', 'mangle', 'nat', 'raw'], answer: 2, explanation: 'Las travesuras de Modificación de IPs origen SNat y Port Forward publicos Dnat se delegan y registran exclusivamente cruzando el filtro de la tabla "nat".' },
  { id: 'lpic2-212-2', topicId: 13, question: 'Ante ataques reiterativos, fuerza-brutales automáticas en Logs Auth SSHd Web.. ¿Qué herramienta python residente protege dinámicamente tu Host interrumpiendo IPs e instalando Jail Banning automático de firewall temporal sobre los atacantes detectados del Log?', options: ['Snort', 'Fail2ban', 'Nmap', 'OpenVAS'], answer: 1, explanation: 'El Guardian por excelencia per el "BruteForce" es Fail2Ban. Vigila las expresiones en formato syslog de auth log y si ve "Failed pass 4 times" dispara una regla drop Netfilter de penalización IP.' },
  { id: 'lpic2-212-3', topicId: 13, question: 'Durante Pentest u orientamiento CiberSeguridad.. La Aplicación CLI por la cual se hace "Scouting" mapeando a ciegas de Hosts up y Servicios o Agujeros IP expuestos tras enumeración de UDP/TCP port con Scripts LUA...', options: ['tcpdump stream capture', 'wireshark analizer LAN', 'nmap portscan footprint and version checker', 'ping sweeping scanner'], answer: 2, explanation: 'El todoterreno "NMAP" escanea de múltiples facetas con agresividades altas o sigilosamente la radiografía de un activo y puertos expuestos.' },
  { id: 'lpic2-212-4', topicId: 13, question: '¿Si en los requerimientos te exigen que presentes un Audit Server formal, qué Suite de Vulnerability Scanner derivó del proyecto antiguo Nessus para cubrir masivas búsquedas sistémicas mediante tests en vivo a corporaciones?', options: ['Una Shell script de Bash para Fail2Ban', 'La Suite Corporativa "OpenVAS" Vulnerability Assessment System', 'VPN OpenVpn con IPsec L2tp', 'S.M.A.R.T. hardware tests.'], answer: 1, explanation: 'Ecosistema masivo apoyado por la comunidad GVM. Chequea debilidades y CVE conocidos contrastando Hosts activos e informando el GAP de remediación y patches requeridos críticos.' },
  { id: 'lpic2-212-5', topicId: 13, question: 'Para la Tabla Fundamental Filter de Iptables; ¿qué instrucción CLI condena por defecto de inicio y radicalmente todas y cada una de las tramas de Datos y Paquetes IP a ser rechazados (Deafult Policy Bloqueadora al Muro de Input)?', options: ['iptables -A INPUT -j DROP', 'iptables -P INPUT DROP', 'iptables -I INPUT DROP', 'iptables -D INPUT DROP'], answer: 1, explanation: 'P dicta "Policy" (La filosofía inalterable si la trama entrante NO choca coincidiendo explícitamente con reglas Append de la tabla, caerá por fin y omisión al fondo al Drop por ser desconocida).' },
  // --- NUEVO BATCH 1 (Temas 200-204) ---
  { id: 'lpic2-200-6', topicId: 1, question: 'En la salida de `vmstat`, ¿qué indica la columna `wa`?', options: ['Espera de CPU', 'Espera de I/O', 'Espera de red', 'Espera de asignación de memoria'], answer: 1, explanation: 'La columna `wa` en `vmstat` muestra el porcentaje de tiempo que la CPU estuvo inactiva mientras el sistema tenía solicitudes de I/O de disco pendientes.' },
  { id: 'lpic2-200-7', topicId: 1, question: '¿Qué comando proporciona un resumen rápido de los promedios de carga (load averages) del sistema para los últimos 1, 5 y 15 minutos?', options: ['w', 'uptime', 'Tanto A como B', 'sar'], answer: 2, explanation: 'Tanto el comando `w` como `uptime` muestran los promedios de carga del sistema.' },
  { id: 'lpic2-200-8', topicId: 1, question: '¿Cuál es el protocolo principal utilizado por MRTG para recopilar datos de dispositivos de red?', options: ['SSH', 'SMTP', 'SNMP', 'HTTP'], answer: 2, explanation: 'MRTG (Multi Router Traffic Grapher) se basa principalmente en SNMP (Simple Network Management Protocol) para recopilar métricas.' },
  { id: 'lpic2-200-9', topicId: 1, question: '¿Qué comando muestra las estadísticas de las interfaces de red, incluyendo paquetes descartados y errores de desbordamiento (overrun)?', options: ['netstat -i', 'netstat -r', 'netstat -tulnp', 'ifconfig -a'], answer: 0, explanation: '`netstat -i` muestra una tabla de todas las interfaces de red y sus estadísticas de transmisión/recepción.' },
  { id: 'lpic2-200-10', topicId: 1, question: '¿Qué valor de memoria en la salida del comando `free` es más indicativo de la memoria disponible para iniciar nuevas aplicaciones sin recurrir al swap?', options: ['total', 'used', 'shared', 'available'], answer: 3, explanation: 'La columna `available` estima cuánta memoria está disponible para iniciar nuevas aplicaciones sin realizar intercambio (swapping).' },
  { id: 'lpic2-200-11', topicId: 1, question: '¿Cómo se configura Collectd para almacenar métricas de manera eficiente a lo largo del tiempo?', options: ['Escribiendo en archivos CSV', 'Escribiendo a través de RRDtool', 'Escribiendo solo en MySQL', 'Escribiendo en syslog'], answer: 1, explanation: 'Collectd a menudo utiliza el plugin RRDtool (Round Robin Database) para almacenar datos de series temporales de manera eficiente.' },
  { id: 'lpic2-200-12', topicId: 1, question: '¿Qué herramienta está diseñada específicamente para mostrar el uso de I/O por proceso en tiempo real, similar a `top`?', options: ['iotop', 'iostat', 'ioping', 'blktrace'], answer: 0, explanation: '`iotop` muestra una interfaz similar a top que presenta el ancho de banda de lectura y escritura de I/O por proceso.' },
  { id: 'lpic2-200-13', topicId: 1, question: '¿Qué sugiere fuertemente un valor alto de `si` y `so` en `vmstat`?', options: ['Congestión de red', 'Cuello de botella en la CPU', 'Escasez de memoria e intercambio (swapping) intenso', 'Fallo de hardware en el disco'], answer: 2, explanation: 'Tasas altas de Swap In (`si`) y Swap Out (`so`) indican que el sistema está utilizando intensamente la memoria en disco debido al agotamiento de la RAM.' },
  { id: 'lpic2-200-14', topicId: 1, question: '¿Qué comando lista todos los sockets TCP y UDP en escucha junto con el PID del proceso?', options: ['ss -tulnp', 'netstat -rn', 'ip route', 'arp -a'], answer: 0, explanation: '`ss -tulnp` (o netstat -tulnp) enumera los puertos TCP/UDP en escucha y sus IDs de proceso relacionados.' },
  { id: 'lpic2-200-15', topicId: 1, question: 'En la planificación de capacidad, ¿qué es una "línea de base" (baseline)?', options: ['La capacidad máxima del servidor', 'La RAM mínima requerida para arrancar', 'Datos históricos que representan el comportamiento normal del sistema', 'El límite físico de la tarjeta de red'], answer: 2, explanation: 'Una línea de base es un estado conocido y normal del sistema registrado a lo largo del tiempo para compararlo con anomalías o crecimiento futuro.' },

  { id: 'lpic2-201-6', topicId: 2, question: '¿Qué comando limpia completamente el árbol de fuentes del kernel, eliminando todos los archivos construidos y el archivo .config?', options: ['make clean', 'make mrproper', 'make distclean', 'make wipe'], answer: 1, explanation: '`make mrproper` elimina todos los archivos generados, incluyendo `.config` y varios archivos de respaldo, garantizando un árbol de fuentes limpio.' },
  { id: 'lpic2-201-7', topicId: 2, question: '¿Cuál es el propósito del comando `depmod`?', options: ['Eliminar un módulo', 'Generar el archivo modules.dep para modprobe', 'Visualizar detalles de los módulos', 'Compilar módulos'], answer: 1, explanation: '`depmod` analiza los módulos del kernel y genera una lista de dependencias (`modules.dep`) utilizada por `modprobe`.' },
  { id: 'lpic2-201-8', topicId: 2, question: '¿Qué herramienta reconstruye dinámicamente módulos del kernel para controladores de terceros (como Nvidia) al instalar un nuevo kernel?', options: ['depmod', 'dracut', 'DKMS', 'kmod'], answer: 2, explanation: 'DKMS (Dynamic Kernel Module Support) es un marco de trabajo que recompila módulos externos del kernel cada vez que se instala un nuevo kernel.' },
  { id: 'lpic2-201-9', topicId: 2, question: '¿Cómo puedes ver la configuración actualmente activa del kernel en ejecución (si el kernel lo permite)?', options: ['cat /proc/kcore', 'zcat /proc/config.gz', 'cat /sys/kernel/config', 'dmesg | grep config'], answer: 1, explanation: 'Si la opción `IKCONFIG_PROC` está habilitada, la configuración del kernel actual se expone en `/proc/config.gz`.' },
  { id: 'lpic2-201-10', topicId: 2, question: '¿Qué comando lista todos los módulos del kernel cargados actualmente?', options: ['lsmod', 'modinfo', 'modprobe -l', 'infomod'], answer: 0, explanation: '`lsmod` formatea el contenido de `/proc/modules` para mostrar qué módulos del kernel están cargados en memoria.' },
  { id: 'lpic2-201-11', topicId: 2, question: '¿Cuál es la diferencia principal entre `initrd` e `initramfs`?', options: ['initrd es un archivo cpio; initramfs es una imagen de dispositivo de bloque', 'initramfs es un archivo cpio extraído en un tmpfs; initrd es una imagen de dispositivo de bloque', 'initrd es solo para UEFI', 'initramfs no puede cargar módulos'], answer: 1, explanation: '`initramfs` es un enfoque moderno y simple que utiliza un archivo cpio comprimido cargado en un tmpfs, evitando los controladores de dispositivos de bloque al inicio del arranque.' },
  { id: 'lpic2-201-12', topicId: 2, question: '¿Qué comando muestra información sobre un módulo del kernel, como el autor, la descripción y los parámetros aceptados?', options: ['lsmod', 'modprobe -d', 'modinfo', 'insmod -i'], answer: 2, explanation: '`modinfo` extrae e imprime la información del propio archivo de objeto del módulo.' },
  { id: 'lpic2-201-13', topicId: 2, question: '¿Qué comando lee `sysctl.conf` y aplica los parámetros del kernel inmediatamente?', options: ['sysctl -w', 'sysctl -a', 'sysctl -p', 'sysctl -r'], answer: 2, explanation: '`sysctl -p` carga parámetros de configuración desde `/etc/sysctl.conf` (o el archivo especificado) al kernel activo.' },
  { id: 'lpic2-201-14', topicId: 2, question: '¿Dónde busca `udev` sus reglas personalizadas para eventos de hardware?', options: ['/etc/udev/rules.d/', '/lib/udev/rules.d/', 'Tanto A como B', '/var/run/udev/'], answer: 2, explanation: '`udev` lee reglas predeterminadas de `/lib/udev/rules.d/` y reglas personalizadas del administrador de `/etc/udev/rules.d/`.' },
  { id: 'lpic2-201-15', topicId: 2, question: '¿Qué comando elimina un módulo del kernel en ejecución si ya no se está usando?', options: ['rmmod', 'insmod -r', 'modprobe -r', 'Tanto A como C'], answer: 3, explanation: 'Tanto `rmmod` como `modprobe -r` se pueden usar para eliminar módulos; `modprobe -r` también elimina limpiamente las dependencias no utilizadas.' },

  { id: 'lpic2-202-6', topicId: 3, question: 'En systemd, ¿qué comando establece el objetivo predeterminado a Gráfico (equivalente al runlevel 5)?', options: ['systemctl set-default graphical.target', 'systemctl isolate graphical.target', 'systemctl default graphical.target', 'ln -s /lib/systemd/system/graphical.target /etc/inittab'], answer: 0, explanation: '`systemctl set-default` cambia el objetivo de arranque predeterminado actualizando el enlace simbólico `/etc/systemd/system/default.target`.' },
  { id: 'lpic2-202-7', topicId: 3, question: 'Durante el arranque de GRUB 2, ¿qué tecla se suele presionar para acceder al menú de arranque y editar los parámetros del kernel si está oculto?', options: ['F8', 'F12', 'Shift o Esc', 'Enter'], answer: 2, explanation: 'Mantener presionado `Shift` (sistemas BIOS) o presionar `Esc` (sistemas UEFI) interrumpe el arranque de GRUB 2 y muestra el menú.' },
  { id: 'lpic2-202-8', topicId: 3, question: '¿Qué hace el comando `systemctl isolate`?', options: ['Reinicia el sistema', 'Cambia el estado operativo actual a un nuevo objetivo, deteniendo servicios innecesarios', 'Deshabilita las interfaces de red', 'Realiza un chroot en otro entorno'], answer: 1, explanation: '`isolate` cambia inmediatamente el sistema a un nuevo objetivo (como cambiar de runlevel en SysV).' },
  { id: 'lpic2-202-9', topicId: 3, question: '¿Qué archivo contiene los ajustes globales (como tiempo de espera y entrada predeterminada) utilizados por grub-mkconfig para generar la configuración de GRUB 2?', options: ['/etc/grub.d/00_header', '/boot/grub/grub.cfg', '/etc/default/grub', '/boot/grub/menu.lst'], answer: 2, explanation: '`/etc/default/grub` contiene variables como `GRUB_TIMEOUT` y `GRUB_CMDLINE_LINUX` que dictan cómo se genera el archivo final.' },
  { id: 'lpic2-202-10', topicId: 3, question: '¿Qué es PXE?', options: ['Un formato de tabla de particiones', 'Un método para arrancar un sistema operativo a través de una red usando DHCP y TFTP', 'Un cargador de arranque de Linux para ARM', 'Un tipo de unidad de systemd'], answer: 1, explanation: 'Preboot eXecution Environment (PXE) permite que las tarjetas de red recuperen un cargador de arranque y un kernel de un servidor de red.' },
  { id: 'lpic2-202-11', topicId: 3, question: '¿Qué directorio contiene los scripts modulares ejecutados por `grub-mkconfig`?', options: ['/etc/default/grub', '/etc/grub.d/', '/boot/grub/scripts/', '/lib/grub/'], answer: 1, explanation: 'El directorio `/etc/grub.d/` contiene scripts ejecutables (como 10_linux) que analizan el sistema durante la generación de grub.cfg.' },
  { id: 'lpic2-202-12', topicId: 3, question: '¿Qué es `systemd-boot`?', options: ['Un envoltorio de SysVinit', 'Un gestor de arranque UEFI ligero', 'Un plugin para GRUB', 'Un tema de Plymouth'], answer: 1, explanation: '`systemd-boot` (anteriormente gummiboot) es un cargador de arranque UEFI simple incorporado en systemd.' },
  { id: 'lpic2-202-13', topicId: 3, question: 'Si pierdes la contraseña de root, ¿qué parámetro del kernel deberías pasar en GRUB para saltarte la autenticación?', options: ['root=/dev/null', 'init=/bin/bash', 'skip_auth=1', 'runlevel=0'], answer: 1, explanation: 'Añadir `init=/bin/bash` (o /bin/sh) monta root e inicia inmediatamente una shell de root sin pedir contraseña.' },
  { id: 'lpic2-202-14', topicId: 3, question: '¿Qué comando genera un disco RAM inicial (initramfs) en sistemas Red Hat / CentOS?', options: ['mkinitcpio', 'mkinitrd / dracut', 'update-initramfs', 'initramfs-build'], answer: 1, explanation: 'Los sistemas basados en RHEL históricamente usaban `mkinitrd` y ahora usan nativamente `dracut` para construir el initramfs.' },
  { id: 'lpic2-202-15', topicId: 3, question: 'En SysVinit, ¿qué script es típicamente responsable de ejecutar los scripts rc para el runlevel definido?', options: ['/etc/rc.local', '/etc/init.d/rc', '/sbin/runlevel', '/bin/sh'], answer: 1, explanation: 'El script `/etc/init.d/rc` es invocado por init con el runlevel como argumento para iniciar/detener los servicios apropiados en `/etc/rcX.d/`.' },

  { id: 'lpic2-203-6', topicId: 4, question: '¿Qué comando muestra la geometría del hardware y las particiones de un disco?', options: ['df -h', 'lsblk', 'fdisk -l', 'Tanto B como C'], answer: 3, explanation: 'Tanto `lsblk` como `fdisk -l` describen los dispositivos de bloques y las particiones (fdisk muestra detalles de la geometría).' },
  { id: 'lpic2-203-7', topicId: 4, question: '¿Qué comando convierte un sistema de archivos ext3 a ext4 sin pérdida de datos?', options: ['tune2fs -O extents,uninit_bg,dir_index /dev/sda1', 'mkfs.ext4 /dev/sda1', 'fsck.ext4 -y /dev/sda1', 'parted /dev/sda1 convert ext4'], answer: 0, explanation: '`tune2fs` permite activar características del sistema de archivos en un disco existente; activar características de ext4 lo convierte efectivamente.' },
  { id: 'lpic2-203-8', topicId: 4, question: '¿Qué herramienta cambia el UUID de un sistema de archivos ext2/ext3/ext4?', options: ['uuidgen', 'blkid', 'tune2fs -U', 'xfs_admin'], answer: 2, explanation: '`tune2fs -U [UUID|random] /dev/sdX` cambia el identificador UUID del sistema de archivos en sistemas ext.' },
  { id: 'lpic2-203-9', topicId: 4, question: '¿Qué opción en `/etc/fstab` monta el sistema de archivos como solo lectura?', options: ['rw', 'ro', 'noexec', 'nosuid'], answer: 1, explanation: 'La opción `ro` especifica el montaje como Read-Only.' },
  { id: 'lpic2-203-10', topicId: 4, question: '¿Qué comando proporciona información sobre el estado y la fragmentación de un sistema de archivos XFS?', options: ['xfs_repair', 'xfs_info', 'xfs_db', 'Ninguno de los anteriores'], answer: 1, explanation: '`xfs_info` imprime detalles de la geometría y el diseño de un sistema de archivos XFS montado.' },
  { id: 'lpic2-203-11', topicId: 4, question: '¿Cómo puedes borrar de forma segura un disco duro (/dev/sdb) sobrescribiéndolo con datos aleatorios?', options: ['dd if=/dev/urandom of=/dev/sdb bs=1M', 'rm -rf /dev/sdb', 'mkfs.ext4 /dev/sdb', 'fdisk -w /dev/sdb'], answer: 0, explanation: 'Usar `dd` para leer de `/dev/urandom` sobrescribe físicamente el disco de destino con datos binarios impredecibles.' },
  { id: 'lpic2-203-12', topicId: 4, question: '¿Qué hace el comando `badblocks`?', options: ['Formatea el disco', 'Escanea un dispositivo en busca de sectores físicamente dañados', 'Repara el log del sistema de archivos', 'Identifica RAM defectuosa'], answer: 1, explanation: '`badblocks` realiza pruebas de lectura/escritura en los sectores para identificar bloques físicamente inutilizables en el almacenamiento.' },
  { id: 'lpic2-203-13', topicId: 4, question: '¿Qué comando de Btrfs crea una instantánea (snapshot) de lectura/escritura de un subvolumen?', options: ['btrfs subvolume snapshot', 'btrfs snap create', 'lvcreate -s', 'btrfs-image'], answer: 0, explanation: '`btrfs subvolume snapshot <origen> <destino>` crea una instantánea de tipo Copy-on-Write.' },
  { id: 'lpic2-203-14', topicId: 4, question: '¿Qué es `autofs`?', options: ['Una herramienta para formatear discos', 'Un demonio que monta automáticamente sistemas de archivos bajo demanda', 'Un sustituto de GRUB', 'Un enrutador de paquetes de red'], answer: 1, explanation: '`autofs` proporciona el montaje automático (montar solo cuando un usuario accede a un directorio específico) y el desmontaje automático.' },
  { id: 'lpic2-203-15', topicId: 4, question: '¿Qué comando de autoría de medios ópticos crea una imagen de sistema de archivos ISO9660?', options: ['cdrecord', 'mkisofs', 'growisofs', 'wodim'], answer: 1, explanation: '`mkisofs` (o genisoimage) toma un árbol de directorios y genera un archivo de diseño ISO9660 adecuado para grabar.' },

  { id: 'lpic2-204-6', topicId: 5, question: 'En LVM, ¿cómo se reduce de forma segura el tamaño de un volumen lógico?', options: ['lvresize -L -10G /dev/vg/lv', 'Reducir primero el tamaño del sistema de archivos dentro del LV, luego reducir el LV', 'Reducir primero el LV, luego reducir el sistema de archivos', 'No se puede reducir un LV'], answer: 1, explanation: 'Debes reducir el sistema de archivos (ej. resize2fs) ANTES de reducir el LV para evitar corromper los límites de los datos.' },
  { id: 'lpic2-204-7', topicId: 5, question: 'Al gestionar un array RAID 5 por software con `mdadm`, ¿qué sucede si falla un disco?', options: ['Los datos se pierden permanentemente', 'El array opera en modo degradado usando la paridad para calcular los datos faltantes', 'El sistema entra inmediatamente en kernel panic', 'El array cambia a RAID 0'], answer: 1, explanation: 'RAID 5 puede tolerar exactamente el fallo de un disco, operando en "modo degradado" hasta que sea reconstruido.' },
  { id: 'lpic2-204-8', topicId: 5, question: '¿Qué comando inicia una sesión iSCSI para descubrir los objetivos (targets) en un servidor?', options: ['iscsiadm -m discovery -t sendtargets -p <IP>', 'iscsid --scan', 'mount -t iscsi', 'lvscan'], answer: 0, explanation: '`iscsiadm` es la herramienta de línea de comandos para interactuar con el iniciador open-iscsi para descubrimiento y login.' },
  { id: 'lpic2-204-9', topicId: 5, question: '¿Qué muestra el comando de LVM `vgdisplay`?', options: ['Solo los volúmenes físicos', 'Solo los volúmenes lógicos', 'Atributos del Volume Group como el tamaño total, PEs libres y PEs asignados', 'Los UUID del sistema de archivos'], answer: 2, explanation: '`vgdisplay` muestra metadatos sobre los Volume Groups, incluyendo detalles de la capacidad de los Physical Extents (PE).' },
  { id: 'lpic2-204-10', topicId: 5, question: '¿Cómo se añade un disco de repuesto (spare) a un array RAID de `mdadm` existente (/dev/md0)?', options: ['mdadm --add /dev/md0 /dev/sdX', 'mdadm --grow /dev/md0 --size=spare', 'mdadm --create /dev/md0 /dev/sdX', 'No se pueden añadir repuestos a arrays activos'], answer: 0, explanation: 'El flag `--add` (o `-a`) añade en caliente un dispositivo de repuesto a un array existente.' },
  { id: 'lpic2-204-11', topicId: 5, question: '¿Cuál es el propósito de los snapshots de LVM?', options: ['Crear copias de seguridad permanentes en cinta', 'Capturar el estado de un volumen lógico instantáneamente (Copy-on-Write) para copias de seguridad consistentes', 'Acelerar las lecturas de disco', 'Convertir ext4 a xfs'], answer: 1, explanation: 'Los snapshots rastrean cambios mediante CoW, permitiéndote respaldar un estado congelado en el tiempo de un volumen sin tiempo de inactividad.' },
  { id: 'lpic2-204-12', topicId: 5, question: 'En un entorno iSCSI, ¿qué es un IQN?', options: ['Internal Query Network', 'iSCSI Qualified Name', 'Internet Quota Node', 'Initial Queue Number'], answer: 1, explanation: 'iSCSI Qualified Name (IQN) es un identificador único global para iniciadores y objetivos iSCSI.' },
  { id: 'lpic2-204-13', topicId: 5, question: '¿Qué flag de `hdparm` obtiene o establece el tiempo de inactividad (spindown) para una unidad?', options: ['-S', '-y', '-Z', '-B'], answer: 0, explanation: '`hdparm -S` establece el tiempo de espera de spindown para una unidad IDE/SATA/SAS.' },
  { id: 'lpic2-204-14', topicId: 5, question: '¿Qué archivo almacena dinámicamente el estado y los detalles de los arrays RAID por software de `mdadm`?', options: ['/etc/mdadm.conf', '/proc/mdstat', '/var/log/raid.log', '/sys/block/raid'], answer: 1, explanation: '`/proc/mdstat` proporciona un resumen en tiempo real de los arrays RAID por software del kernel y su estado de sincronización.' },
  { id: 'lpic2-204-15', topicId: 5, question: '¿Qué componente de LVM se crea directamente sobre una partición de disco cruda?', options: ['Logical Volume (LV)', 'Volume Group (VG)', 'Physical Volume (PV)', 'Volume Extent (VE)'], answer: 2, explanation: 'Un Physical Volume (PV) es la estructura básica de LVM creada directamente en un disco o partición.' },

  // --- NUEVO BATCH 2 (Temas 205-208) ---
  { id: 'lpic2-205-6', topicId: 6, question: '¿Qué comando `ip` asigna la dirección IPv4 192.168.1.10/24 a la interfaz eth0?', options: ['ip address add 192.168.1.10/24 dev eth0', 'ip addr set eth0 192.168.1.10/24', 'ip assign eth0 192.168.1.10/24', 'ifconfig eth0 add 192.168.1.10/24'], answer: 0, explanation: '`ip address add <dirección> dev <interfaz>` es la sintaxis correcta.' },
  { id: 'lpic2-205-7', topicId: 6, question: '¿Cuál es el propósito del archivo `/etc/iproute2/rt_tables`?', options: ['Almacena la caché ARP del sistema', 'Mapea los IDs de las tablas de enrutamiento a nombres legibles por humanos', 'Configura las reglas del firewall para iproute2', 'Asigna direcciones IP estáticas'], answer: 1, explanation: 'Este archivo permite a los administradores usar nombres simbólicos en lugar de identificadores numéricos para las tablas de enrutamiento.' },
  { id: 'lpic2-205-8', topicId: 6, question: '¿Qué herramienta se usa principalmente para configurar parámetros (como SSID o frecuencia) de una interfaz de red inalámbrica en Linux?', options: ['ifconfig', 'iwconfig', 'wpa_supplicant', 'nmcli'], answer: 1, explanation: '`iwconfig` es una herramienta CLI dedicada a configurar extensiones inalámbricas e interfaces de red inalámbricas.' },
  { id: 'lpic2-205-9', topicId: 6, question: 'Durante una prueba de conexión, ¿cómo le indicas a `ping` que sus paquetes se originen específicamente desde la interfaz `eth1`?', options: ['ping -S eth1', 'ping -I eth1', 'ping -e eth1', 'ping -i eth1'], answer: 1, explanation: 'El flag `-I` vincula explícitamente el socket del ping a una interfaz específica o dirección IP de origen.' },
  { id: 'lpic2-205-10', topicId: 6, question: '¿Qué comando establece una puerta de enlace (gateway) predeterminada de 10.0.0.1 usando la suite iproute2?', options: ['ip route add default via 10.0.0.1', 'route add default gw 10.0.0.1', 'ip route default 10.0.0.1', 'ip gw set 10.0.0.1'], answer: 0, explanation: '`ip route add default via <IP>` añade una regla de enrutamiento para la puerta de enlace predeterminada.' },
  { id: 'lpic2-205-11', topicId: 6, question: '¿Cómo puedes capturar paquetes de red con `tcpdump` y guardarlos en un archivo llamado `capture.pcap` para analizarlos más tarde en Wireshark?', options: ['tcpdump > capture.pcap', 'tcpdump -f capture.pcap', 'tcpdump -w capture.pcap', 'tcpdump -o capture.pcap'], answer: 2, explanation: 'El flag `-w` indica a tcpdump que escriba los paquetes crudos en un archivo PCAP especificado.' },
  { id: 'lpic2-205-12', topicId: 6, question: '¿Qué herramienta de Linux suele llamarse la "navaja suiza" de las redes y puede usarse para el escaneo de puertos, transferencia de archivos y captura de banners?', options: ['nmap', 'nc (netcat)', 'telnet', 'curl'], answer: 1, explanation: 'Netcat (`nc`) es una utilidad versátil utilizada para leer y escribir en conexiones de red a través de TCP o UDP.' },
  { id: 'lpic2-205-13', topicId: 6, question: '¿Cuál es la dirección IPv6 de loopback equivalente a 127.0.0.1?', options: ['::1', 'fe80::1', '0:0:0:0:0:0:0:1', 'Tanto A como C'], answer: 3, explanation: '`::1` es el formato abreviado de `0:0:0:0:0:0:0:1`, que es la dirección de localhost en IPv6.' },
  { id: 'lpic2-205-14', topicId: 6, question: '¿Qué opción de la utilidad `ss` muestra todos los sockets en escucha *y* los establecidos (no en escucha)?', options: ['ss -l', 'ss -a', 'ss -t', 'ss -u'], answer: 1, explanation: '`ss -a` (all) imprime tanto los sockets en escucha como los que no están en escucha.' },
  { id: 'lpic2-205-15', topicId: 6, question: '¿Por defecto, qué tipo de paquete envía el comando tradicional de Linux `traceroute` para sondear la ruta?', options: ['TCP SYN', 'ICMP Echo Request', 'Datagramas UDP', 'Consultas IGMP'], answer: 2, explanation: 'A diferencia del `tracert` de Windows que usa ICMP, el `traceroute` estándar de Linux utiliza datagramas UDP dirigidos a puertos altos con números incrementales.' },

  { id: 'lpic2-206-6', topicId: 7, question: '¿Qué utilidad puede reemplazar a `make install` para crear un paquete Slackware, RPM o Debian a partir del código fuente compilado para facilitar su eliminación posterior?', options: ['autotools', 'checkinstall', 'dpkg-buildpackage', 'rpmbuild'], answer: 1, explanation: '`checkinstall` rastrea los archivos instalados por `make install` y crea un paquete (como .deb o .rpm) para una gestión limpia de los paquetes.' },
  { id: 'lpic2-206-7', topicId: 7, question: '¿Qué herramienta rastrea las llamadas a bibliotecas dinámicas realizadas por un ejecutable (a diferencia de las llamadas al sistema)?', options: ['strace', 'ltrace', 'ldd', 'objdump'], answer: 1, explanation: '`ltrace` intercepta y registra las llamadas a bibliotecas dinámicas vinculadas a un ejecutable durante su ejecución.' },
  { id: 'lpic2-206-8', topicId: 7, question: 'Al extraer un tarball comprimido con `bzip2`, ¿qué flag típico se pasa a `tar`?', options: ['-z', '-J', '-j', '-b'], answer: 2, explanation: 'El flag `-j` indica a GNU tar que descomprima usando bzip2.' },
  { id: 'lpic2-206-9', topicId: 7, question: '¿Qué comando controla las operaciones de las unidades de cinta magnética, como rebobinar y expulsar?', options: ['tape', 'mt', 'tar', 'cpio'], answer: 1, explanation: '`mt` (magnetic tape) es la utilidad estándar invocada para controlar los mecanismos físicos de las unidades de cinta.' },
  { id: 'lpic2-206-10', topicId: 7, question: 'En `rsync`, ¿qué hace el flag `-a` (archive)?', options: ['Comprime los datos', 'Sincroniza recursivamente y preserva permisos, tiempos, propietarios y enlaces simbólicos', 'Elimina archivos extraños del destino', 'Copia solo archivos ocultos'], answer: 1, explanation: 'El modo archivo (`-a`) es equivalente a `-rlptgoD`, lo que lo hace ideal para realizar sincronizaciones de directorios idénticas.' },
  { id: 'lpic2-206-11', topicId: 7, question: '¿Qué comando de systemd le indica a un demonio que simplemente vuelva a leer sus archivos de configuración sin perder las conexiones activas?', options: ['systemctl restart', 'systemctl reload', 'systemctl force-reload', 'systemctl refresh'], answer: 1, explanation: '`reload` indica de forma segura a un servicio que vuelva a procesar sus configuraciones sin una interrupción brusca.' },
  { id: 'lpic2-206-12', topicId: 7, question: '¿Cuál es la estructura de directorio estándar en un sistema de archivos de Linux designada específicamente para contener la mayoría de los logs de servicios genéricos?', options: ['/usr/log/', '/var/spool/log/', '/var/log/', '/etc/logs/'], answer: 2, explanation: 'El directorio `/var/log/` es el estándar que cumple con la FHS para la salida de logs del sistema y las aplicaciones.' },
  { id: 'lpic2-206-13', topicId: 7, question: '¿Cómo se puede adjuntar `strace` a un proceso demonio que ya se está ejecutando?', options: ['strace -a <PID>', 'strace -p <PID>', 'strace --attach <PID>', 'strace <PID>'], answer: 1, explanation: 'El flag `-p` fuerza a strace a engancharse dinámicamente al ID de proceso especificado.' },
  { id: 'lpic2-206-14', topicId: 7, question: 'Al crear una copia de seguridad exacta bit a bit de una partición de disco con `dd`, ¿qué parámetro define el tamaño de los bloques leídos/escritos para mejorar drásticamente la velocidad?', options: ['count=', 'bs=', 'size=', 'chunk='], answer: 1, explanation: '`bs` (block size) dicta la cantidad de bytes leídos y escritos a la vez, por ejemplo: `bs=4M`.' },
  { id: 'lpic2-206-15', topicId: 7, question: '¿Qué comando genera un par de llaves de autenticación OpenSSH?', options: ['ssh-agent', 'ssh-add', 'ssh-keygen', 'ssh-copy-id'], answer: 2, explanation: '`ssh-keygen` genera matemáticamente pares de llaves pública y privada para la autenticación del protocolo SSH.' },

  { id: 'lpic2-207-6', topicId: 8, question: '¿Qué define el registro Start of Authority (SOA) en un archivo de zona de BIND?', options: ['La dirección IP del servidor web', 'Información autoritativa sobre la zona, incluyendo el correo del administrador y parámetros de temporización', 'Un listado de todos los subdominios', 'Datos de geolocalización para el dominio'], answer: 1, explanation: 'El registro SOA es obligatorio en todas las zonas y contiene parámetros críticos como el número de serie, tiempos de refresco y TTL negativo.' },
  { id: 'lpic2-207-7', topicId: 8, question: '¿Qué tipo de registro DNS se utiliza para crear un alias de un nombre a otro nombre (FQDN)?', options: ['A', 'PTR', 'CNAME', 'TXT'], answer: 2, explanation: 'Un registro CNAME (Canonical Name) mapea un nombre de alias al verdadero nombre canónico del dominio.' },
  { id: 'lpic2-207-8', topicId: 8, question: 'En Linux, ¿qué utilidad versátil se prefiere para consultar servidores DNS y depurar problemas de resolución de nombres frente a `nslookup`?', options: ['dig', 'host', 'ping', 'whois'], answer: 0, explanation: '`dig` (Domain Information Groper) proporciona una salida detallada y flexible indispensable para los administradores de DNS.' },
  { id: 'lpic2-207-9', topicId: 8, question: 'Para permitir la resolución inversa (de IP a nombre), ¿bajo qué dominio especial debe configurarse la zona en el DNS?', options: ['.reverse', '.in-addr.arpa', '.ip6.arpa', 'Tanto B como C'], answer: 3, explanation: '`in-addr.arpa` gestiona la resolución inversa para IPv4, mientras que `ip6.arpa` se dedica a IPv6.' },
  { id: 'lpic2-207-10', topicId: 8, question: '¿Qué archivo de configuración local del sistema operativo Linux indica qué resolvers (servidores DNS) consultar primero?', options: ['/etc/hosts', '/etc/resolv.conf', '/etc/nsswitch.conf', '/etc/named.conf'], answer: 1, explanation: '`/etc/resolv.conf` enumera las directivas `nameserver` que el sistema usa para resolver consultas DNS.' },
  { id: 'lpic2-207-11', topicId: 8, question: '¿Qué comando recarga la configuración del servidor BIND (`named`) sin terminar el proceso?', options: ['named -r', 'service named restart', 'rndc reload', 'bind-init reload'], answer: 2, explanation: '`rndc` (Remote Name Daemon Control) es la utilidad de administración de BIND; el subcomando `reload` aplica los cambios de zona de forma segura.' },
  { id: 'lpic2-207-12', topicId: 8, question: 'En una configuración de DNSSEC, ¿qué registro se inserta en la zona padre para establecer una "cadena de confianza" hacia la zona hija?', options: ['RRSIG', 'DS (Delegation Signer)', 'DNSKEY', 'NSEC'], answer: 1, explanation: 'El registro DS contiene el hash de la llave DNSKEY de la zona delegada y reside en la zona del padre.' },
  { id: 'lpic2-207-13', topicId: 8, question: '¿Qué es TSIG en el contexto de BIND?', options: ['Un protocolo para el enrutamiento de DNS', 'Una firma de transacción que usa llaves secretas compartidas para autenticar transferencias de zona y actualizaciones dinámicas', 'Un tipo de registro para streaming de video', 'Una herramienta para comprimir logs de BIND'], answer: 1, explanation: 'TSIG garantiza que las comunicaciones entre servidores DNS (como transferencias de zona) estén autenticadas mediante una llave secreta.' },
  { id: 'lpic2-207-14', topicId: 8, question: '¿Qué campo en el archivo de zona debe incrementarse cada vez que se realiza un cambio para que los servidores esclavos sepan que deben actualizarse?', options: ['Refresh', 'Retry', 'Serial Number', 'Expire'], answer: 2, explanation: 'El Serial Number es comparado por los servidores esclavos; si es mayor al almacenado localmente, se inicia una petición de transferencia (AXFR/IXFR).' },
  { id: 'lpic2-207-15', topicId: 8, question: 'Para proteger el sistema principal en caso de compromiso, ¿en qué entorno aislado se ejecuta a menudo BIND?', options: ['Una partición NTFS', 'Un Chroot jail', 'Un directorio LDAP', 'Un snapshot de LVM'], answer: 1, explanation: 'Ejecutar BIND en una "jaula" chroot limita el acceso del demonio a solo un subconjunto restringido del sistema de archivos.' },

  { id: 'lpic2-208-6', topicId: 9, question: 'En Apache, ¿qué directiva define el directorio principal desde el cual se sirven los archivos del sitio web?', options: ['ServerRoot', 'DocumentRoot', 'DirectoryIndex', 'PathRoot'], answer: 1, explanation: '`DocumentRoot` mapea la URL raíz (/) a un directorio físico en el servidor Linux.' },
  { id: 'lpic2-208-7', topicId: 9, question: 'Para configurar Nginx como Reverse Proxy, ¿qué directiva se usa dentro de un bloque `location` para reenviar peticiones a un servidor backend?', options: ['proxy_pass', 'proxy_forward', 'redirect_to', 'upstream_pass'], answer: 0, explanation: '`proxy_pass` define el protocolo y la dirección del servidor proxy al que se le deben reenviar las peticiones (ej. http://localhost:8080).' },
  { id: 'lpic2-208-8', topicId: 9, question: '¿Qué módulo de Apache permite la manipulación dinámica de las URLs entrantes mediante expresiones regulares?', options: ['mod_alias', 'mod_rewrite', 'mod_proxy', 'mod_env'], answer: 1, explanation: '`mod_rewrite` es un motor potente basado en reglas que permite reescribir URLs al vuelo por SEO o redirecciones.' },
  { id: 'lpic2-208-9', topicId: 9, question: '¿Qué archivo se puede colocar en un subdirectorio del sitio para sobrescribir configuraciones globales de Apache sin reiniciar el servidor?', options: ['.config', '.htaccess', '.apacheconf', 'index.php'], answer: 1, explanation: 'Los archivos `.htaccess` permiten una configuración descentralizada por directorio, aunque pueden impactar en el rendimiento.' },
  { id: 'lpic2-208-10', topicId: 9, question: 'En Squid proxy, ¿qué directiva se usaría para bloquear el acceso a una ACL llamada "red_local"?', options: ['http_access allow red_local', 'http_access deny red_local', 'acl red_local deny', 'block red_local'], answer: 1, explanation: '`http_access deny <nombre_acl>` aplica la regla de prohibición al tráfico que coincida con la definición de la ACL.' },
  { id: 'lpic2-208-11', topicId: 9, question: '¿Cuál es la ventaja principal de la arquitectura dirigida por eventos de Nginx frente al modelo basado en procesos de Apache?', options: ['Soportar más lenguajes de programación', 'Consumir mucha más RAM', 'Puede manejar miles de conexiones simultáneas con un uso mínimo de recursos (RAM/CPU)', 'Es más fácil de configurar para principiantes'], answer: 2, explanation: 'Al usar un diseño asíncrono y no bloqueante, Nginx escala mucho mejor bajo cargas pesadas de conexiones simultáneas.' },
  { id: 'lpic2-208-12', topicId: 9, question: '¿Cómo se define un servidor proxy "padre" (parent) al que Squid debe reenviar peticiones si no puede satisfacerlas localmente?', options: ['cache_peer', 'proxy_parent', 'upstream_proxy', 'neighbor_server'], answer: 0, explanation: 'La directiva `cache_peer` define otros servidores proxy y su rol (padre o hermano) en la jerarquía de caché.' },
  { id: 'lpic2-208-13', topicId: 9, question: 'En Nginx, ¿qué parámetro en el archivo de configuración principal define cuántos procesos hijos deben generarse (típicamente establecido en "auto")?', options: ['worker_connections', 'worker_processes', 'server_spawn', 'thread_pool'], answer: 1, explanation: '`worker_processes` define el número de instancias de trabajo; si es "auto", suele coincidir con el número de núcleos de la CPU.' },
  { id: 'lpic2-208-14', topicId: 9, question: '¿Qué directivas de Apache se usan dentro de un VirtualHost para identificar el nombre de dominio primario y sus nombres alternativos (alias)?', options: ['ServerName / ServerAlias', 'HostName / HostAlias', 'DomainName / DomainAlias', 'VirtualName / VirtualAlias'], answer: 0, explanation: '`ServerName` define el dominio principal, mientras que `ServerAlias` lista otros nombres que coinciden con el mismo VirtualHost.' },
  { id: 'lpic2-208-15', topicId: 9, question: '¿Qué comando fuerza a Squid a releer sus archivos de configuración sin detener el servicio?', options: ['squid reload', 'squid -k reconfigure', 'squid -s', 'service squid restart'], answer: 1, explanation: '`squid -k reconfigure` envía una señal al demonio activo para que vuelva a analizar los ajustes actuales.' },

  // --- NUEVO BATCH 3 (Temas 209-212) ---
  { id: 'lpic2-209-6', topicId: 10, question: '¿Qué comando muestra las conexiones activas actuales y los archivos bloqueados en un servidor Samba?', options: ['smbstatus', 'testparm', 'smbclient', 'netstat -smb'], answer: 0, explanation: '`smbstatus` reporta las conexiones actuales de Samba, incluyendo usuarios, máquinas y archivos bloqueados.' },
  { id: 'lpic2-209-7', topicId: 10, question: 'Antes de reiniciar Samba, ¿qué utilidad deberías usar para comprobar la corrección interna y los errores de sintaxis de `smb.conf`?', options: ['smb-check', 'testparm', 'smbclient -t', 'smbpasswd -check'], answer: 1, explanation: '`testparm` lee `smb.conf` y lo chequea en busca de errores de análisis (parsing) de la configuración.' },
  { id: 'lpic2-209-8', topicId: 10, question: '¿Qué comando permite a un usuario de escritorio Linux navegar y transferir archivos interactivamente desde un recurso compartido de red de Windows de forma similar a FTP?', options: ['mount.cifs', 'winbound', 'smbclient', 'samba-ftpd'], answer: 2, explanation: '`smbclient` es un cliente similar a un cliente FTP para acceder a recursos SMB/CIFS en servidores.' },
  { id: 'lpic2-209-9', topicId: 10, question: '¿Qué diferencia arquitectónica importante distingue a NFSv4 de NFSv3?', options: ['NFSv4 usa solo UDP', 'NFSv4 integra el bloqueo de archivos y el montaje en un solo protocolo sobre el puerto TCP 2049, eliminando la necesidad de rpcbind', 'NFSv4 no se puede montar sobre Internet', 'NFSv3 es más rápido para redes de área amplia (WAN)'], answer: 1, explanation: 'NFSv4 es amigable con los firewalls porque consolida el montaje, el bloqueo y la transferencia de archivos en un único puerto (TCP 2049).' },
  { id: 'lpic2-209-10', topicId: 10, question: '¿Qué comando consulta a un servidor NFS remoto (en 192.168.1.50) para ver qué directorios está exportando actualmente?', options: ['showmount -e 192.168.1.50', 'exportfs -v 192.168.1.50', 'nfsstat -m 192.168.1.50', 'mount -l 192.168.1.50'], answer: 0, explanation: '`showmount -e` muestra la lista de exportaciones de un servidor NFS.' },
  { id: 'lpic2-209-11', topicId: 10, question: '¿Qué proporciona el comando `nfsstat`?', options: ['Reinicia el demonio NFS', 'Muestra estadísticas sobre la actividad del cliente y servidor NFS para ayudar a diagnosticar problemas de rendimiento', 'Formatea un disco para NFS', 'Prueba las velocidades de red entre nodos'], answer: 1, explanation: '`nfsstat` muestra estadísticas detalladas sobre RPC (Remote Procedure Call) y el sistema de archivos de red (NFS).' },
  { id: 'lpic2-209-12', topicId: 10, question: 'En configuraciones avanzadas de Samba, ¿qué demonio mapea los identificadores SID de Windows a UID/GID de Linux asignados en un entorno de Active Directory?', options: ['smbd', 'nmbd', 'winbindd', 'kerberosd'], answer: 2, explanation: '`winbindd` resuelve nombres de servidores NT y proporciona una función de mapeo de ID unificado para los usuarios del dominio.' },
  { id: 'lpic2-209-13', topicId: 10, question: 'El NFS antiguo (v3) dependía fuertemente de un demonio que mapeaba números de programa RPC a números de puerto de red. ¿Cómo se llama este demonio?', options: ['rpcbind (o portmap)', 'inetd', 'xinetd', 'rpc.nfsd'], answer: 0, explanation: '`rpcbind` (antes `portmap`) asigna dinámicamente puertos variables para servicios auxiliares de NFS antiguos como rpc.statd.' },
  { id: 'lpic2-209-14', topicId: 10, question: '¿Qué parámetro global en `smb.conf` dicta el nombre del dominio de Windows o grupo de trabajo en el que aparecerá el servidor Samba?', options: ['domain =', 'netbios name =', 'server string =', 'workgroup ='], answer: 3, explanation: 'El parámetro `workgroup` establece el nombre del grupo de trabajo o dominio.' },
  { id: 'lpic2-209-15', topicId: 10, question: '¿Qué comando monta un recurso compartido de Windows de forma nativa en el árbol del sistema de archivos de Linux?', options: ['mount -t ntfs //server/share /mnt', 'mount -t smbfs //server/share /mnt', 'mount -t cifs -o username=user //server/share /mnt', 'smbclient //server/share /mnt'], answer: 2, explanation: 'El Linux moderno usa el módulo del kernel `cifs` (Virtual File System) para montar recursos compartidos SMB.' },
  { id: 'lpic2-209-16', topicId: 10, question: 'En `/etc/exports`, ¿qué hace el parámetro `no_root_squash`?', options: ['Impide el acceso de root por completo', 'Permite que el usuario root remoto mantenga privilegios de root en el directorio exportado', 'Comprime los archivos accedidos por root', 'Mapea a root al usuario nobody'], answer: 1, explanation: 'Normalmente, NFS aplasta (squash) las peticiones de root a un UID anónimo. `no_root_squash` desactiva este comportamiento, lo que representa un grave riesgo de seguridad si se usa a la ligera.' },

  { id: 'lpic2-210-6', topicId: 11, question: 'En la configuración del servidor DHCP de ISC (`dhcpd.conf`), ¿qué parámetro define cuánto tiempo dura por defecto la asignación (lease) de una IP a un cliente si este no solicita un rango específico?', options: ['max-lease-time', 'default-lease-time', 'lease-duration', 'expire-time'], answer: 1, explanation: '`default-lease-time` es el tiempo de asignación estándar en segundos.' },
  { id: 'lpic2-210-7', topicId: 11, question: '¿Qué demonio de ISC DHCP crea el log centralizado de IPs asignadas, almacenando eficazmente el estado entre reinicios?', options: ['/etc/dhcp/dhcpd.conf', '/var/lib/dhclient/dhclient.leases', '/var/lib/dhcp/dhcpd.leases', '/var/log/dhcpd.log'], answer: 2, explanation: 'El archivo `dhcpd.leases` actúa como una base de datos para rastrear las asignaciones activas.' },
  { id: 'lpic2-210-8', topicId: 11, question: '¿Cuáles son los cuatro grupos de gestión dentro de un archivo de configuración de módulo PAM?', options: ['allow, deny, warn, critical', 'auth, account, password, session', 'user, group, other, root', 'login, shell, network, local'], answer: 1, explanation: 'PAM organiza las reglas en auth (identidad), account (validez), password (actualización de credenciales) y session (configuración/terminación).' },
  { id: 'lpic2-210-9', topicId: 11, question: 'En un stack de PAM, ¿qué sucede si un módulo marcado como `requisite` falla?', options: ['El stack devuelve inmediatamente el fallo sin ejecutar más módulos', 'El fallo se registra, pero se prueba el siguiente módulo', 'El usuario es redirigido a una shell limitada', 'Se le pide al usuario un CAPTCHA'], answer: 0, explanation: 'A diferencia de `required`, `requisite` causa un fallo inmediato evitando cualquier procesamiento posterior.' },
  { id: 'lpic2-210-10', topicId: 11, question: '¿Por defecto, en qué puerto TCP opera LDAP sin cifrar?', options: ['110', '389', '636', '3306'], answer: 1, explanation: 'LDAP se comunica a través del puerto TCP 389, mientras que LDAPS (LDAP sobre SSL) usa el puerto 636.' },
  { id: 'lpic2-210-11', topicId: 11, question: '¿Qué demonio es el motor principal de la suite del servidor OpenLDAP?', options: ['ldap_agent', 'named', 'slapd', 'sssd'], answer: 2, explanation: '`slapd` son las siglas de Stand-Alone LDAP Daemon.' },
  { id: 'lpic2-210-12', topicId: 11, question: '¿Qué utilidad de línea de comandos consulta un directorio LDAP usando filtros?', options: ['ldapquery', 'ldapsearch', 'ldaplookup', 'ldapfind'], answer: 1, explanation: '`ldapsearch` abre una conexión a un servidor LDAP, realiza un bind y busca usando un filtro específico.' },
  { id: 'lpic2-210-13', topicId: 11, question: '¿Qué demonio moderno se usa ampliamente en Linux para cachear credenciales y gestionar conexiones a directorios centralizados como LDAP o Active Directory?', options: ['nscd', 'sssd', 'pam_unix', 'winbind'], answer: 1, explanation: 'System Security Services Daemon (SSSD) integra el sistema con directorios centralizados remotos y proporciona cacheo offline.' },
  { id: 'lpic2-210-14', topicId: 11, question: 'En OpenVPN, ¿enrutar todo el tráfico de internet del cliente a través de la VPN requiere enviar (push) qué directiva específica al cliente?', options: ['push "route 0.0.0.0 0.0.0.0"', 'push "redirect-gateway def1"', 'push "default-route"', 'route-all'], answer: 1, explanation: '`redirect-gateway def1` modifica la tabla de enrutamiento predeterminada del cliente para que apunte al túnel VPN.' },
  { id: 'lpic2-210-15', topicId: 11, question: '¿Qué comando fuerza a un cliente Linux a liberar manualmente su dirección IP de DHCP y detener el demonio?', options: ['dhclient -x', 'dhclient -r', 'ifdown eth0', 'ip addr flush'], answer: 1, explanation: '`dhclient -r` libera explícitamente el lease actual al servidor y detiene el demonio del cliente.' },
  { id: 'lpic2-210-16', topicId: 11, question: '¿Cuál es el sufijo/extensión estándar para el archivo de autoridad de certificación utilizado para autenticar clientes de OpenVPN?', options: ['.key', '.crt', '.csr', '.ca'], answer: 1, explanation: 'Los certificados (llaves públicas) suelen usar la extensión `.crt` o `.pem`.' },

  { id: 'lpic2-211-6', topicId: 12, question: '¿Qué comando muestra el contenido actual de la cola de correo de Postfix?', options: ['mailq', 'postqueue -p', 'Tanto A como B', 'qstat'], answer: 2, explanation: '`mailq` suele ser un enlace simbólico a `postqueue -p`, que imprime la cola.' },
  { id: 'lpic2-211-7', topicId: 12, question: '¿Qué hace el comando de Postfix `postsuper -d ALL`?', options: ['Elimina todos los mensajes de la cola de correo', 'Descarga todos los mensajes del MTA', 'Despliega una nueva configuración del supervisor', 'Desactiva el servidor de correo'], answer: 0, explanation: '`postsuper` gestiona la cola de Postfix; `-d ALL` elimina irrecuperablemente todos los mensajes en cola.' },
  { id: 'lpic2-211-8', topicId: 12, question: '¿Qué parámetro en `main.cf` define para qué nombres de dominio Postfix se considera el destino final?', options: ['myhostname', 'mynetworks', 'mydestination', 'relay_domains'], answer: 2, explanation: 'Los correos electrónicos dirigidos a los dominios enumerados en `mydestination` se entregan localmente.' },
  { id: 'lpic2-211-9', topicId: 12, question: 'Si quieres que Postfix rechace globalmente correos de direcciones IP de spammitas conocidos, ¿qué directiva configurarías para usar DNS Blocklists (DNSBL)?', options: ['smtpd_recipient_restrictions', 'smtpd_client_restrictions', 'header_checks', 'virtual_alias_maps'], answer: 1, explanation: '`smtpd_client_restrictions = reject_rbl_client zen.spamhaus.org` evalúa la IP que se conecta antes de cualquier transacción.' },
  { id: 'lpic2-211-10', topicId: 12, question: '¿Qué puerto está históricamente reservado para el protocolo POP3 (no cifrado)?', options: ['25', '110', '143', '993'], answer: 1, explanation: 'El protocolo Post Office Protocol versión 3 opera en el puerto TCP 110.' },
  { id: 'lpic2-211-11', topicId: 12, question: 'En Dovecot, ¿cuál es el puerto predeterminado para IMAPS (Secure IMAP sobre SSL/TLS)?', options: ['143', '465', '587', '993'], answer: 3, explanation: 'IMAPS utiliza TLS implícitamente seguro en el puerto TCP 993.' },
  { id: 'lpic2-211-12', topicId: 12, question: '¿Qué lenguaje de scripting MDA se considera la alternativa moderna y estandarizada a Procmail, diseñado específicamente para integrarse limpiamente con Dovecot?', options: ['Bash', 'Python', 'Sieve', 'Perl'], answer: 2, explanation: 'Sieve es un lenguaje de scripting altamente seguro y estandarizado para filtrar correos a nivel MTA/MDA.' },
  { id: 'lpic2-211-13', topicId: 12, question: '¿Dónde se definen típicamente las recetas (recipes) de Procmail para cada usuario?', options: ['/etc/procmail.conf', '~/.procmailrc', '/var/spool/mail/recipes', '~/.mailfilter'], answer: 1, explanation: 'Los usuarios crean sus propias recetas de enrutamiento de correo en el archivo `.procmailrc` en sus directorios personales.' },
  { id: 'lpic2-211-14', topicId: 12, question: '¿Cuál es la función del parámetro `mynetworks` en Postfix?', options: ['Bloquea el spam de esas redes', 'Define la lista de redes locales autorizadas para retransmitir (relay) correo a través del servidor hacia dominios externos', 'Mapea direcciones IP locales', 'Define las interfaces IP en las que Postfix escucha'], answer: 1, explanation: 'Los clientes de las IPs que coinciden con `mynetworks` son considerados confiables para el reenvío (relay) de correo.' },
  { id: 'lpic2-211-15', topicId: 12, question: '¿Qué comando fuerza a Postfix a intentar la entrega inmediata de todos los mensajes diferidos (deferred) que esperan en la cola?', options: ['postsuper -r', 'postfix flush', 'postqueue -f', 'mailq -f'], answer: 2, explanation: '`postqueue -f` recorre la cola de correo e intenta un vaciado (flush) inmediato.' },
  { id: 'lpic2-211-16', topicId: 12, question: '¿Qué configura la directiva de Postfix `virtual_alias_maps`?', options: ['Mapea dominios virtuales a direcciones IP físicas', 'Reenvía correos de una dirección específica (ej. info@dominio.com) a buzones reales', 'Mapea IPs externas a servidores internos', 'Crea respuestas automáticas de vacaciones'], answer: 1, explanation: 'Los alias virtuales reescriben las direcciones de los destinatarios, comúnmente utilizados para el reenvío.' },

  { id: 'lpic2-212-6', topicId: 13, question: 'En iptables, ¿qué opción añade una regla al final de una cadena?', options: ['-I', '-A', '-D', '-R'], answer: 1, explanation: '`-A` significa Append, mientras que `-I` inserta una regla al principio (o en un número de línea específico).' },
  { id: 'lpic2-212-7', topicId: 13, question: '¿Qué comando lista todas las reglas de iptables en la tabla NAT?', options: ['iptables -L', 'iptables -t nat -L', 'iptables -nL --table nat', 'iptables --list nat'], answer: 1, explanation: '`-t nat` especifica la tabla de destino y `-L` lista las reglas.' },
  { id: 'lpic2-212-8', topicId: 13, question: '¿Qué cadena de filtrado en iptables maneja los paquetes cuyo destino final es el propio servidor?', options: ['FORWARD', 'OUTPUT', 'INPUT', 'PREROUTING'], answer: 2, explanation: 'La cadena `INPUT` procesa los paquetes entrantes dirigidos a los sockets locales.' },
  { id: 'lpic2-212-9', topicId: 13, question: 'En `iptables`, ¿qué hace el target `MASQUERADE`?', options: ['Oculta los datos del paquete', 'Traduce dinámicamente la IP de origen de los paquetes salientes por la IP de la interfaz de salida', 'Bloquea a hackers conocidos', 'Crea un túnel VPN'], answer: 1, explanation: 'Masquerading es un SNAT dinámico, muy usado en routers con IPs públicas dinámicas.' },
  { id: 'lpic2-212-10', topicId: 13, question: 'Con Nmap, ¿qué especifica el flag `-sS`?', options: ['Escaneo UDP', 'Escaneo TCP SYN (Stealth)', 'Escaneo TCP Connect', 'Escaneo FIN'], answer: 1, explanation: 'El escaneo SYN realiza un apretón de manos (handshake) TCP a medio abrir para mapear puertos de forma eficiente.' },
  { id: 'lpic2-212-11', topicId: 13, question: '¿Qué argumento de línea de comandos le indica a Nmap que intente identificar el sistema operativo del host remoto?', options: ['-O', '-sV', '-A', 'Tanto A como C'], answer: 3, explanation: '`-O` habilita específicamente la detección del SO. `-A` (Agresivo) habilita la detección del SO junto con el escaneo de versiones y scripts.' },
  { id: 'lpic2-212-12', topicId: 13, question: 'En Fail2ban, ¿qué archivo deberían usar los administradores para personalizar las configuraciones de las cárceles (jails) para evitar que las actualizaciones de paquetes las sobrescriban?', options: ['jail.conf', 'fail2ban.conf', 'jail.local', 'iptables.local'], answer: 2, explanation: '`jail.local` sobrescribe a `jail.conf`, actuando como el repositorio seguro para los cambios locales.' },
  { id: 'lpic2-212-13', topicId: 13, question: '¿Qué variable en Fail2ban define la duración (en segundos) que una IP infractora permanece bloqueada?', options: ['blocktime', 'findtime', 'maxretry', 'bantime'], answer: 3, explanation: '`bantime` define cuánto tiempo se mantiene en vigor la inserción del DROP de iptables.' },
  { id: 'lpic2-212-14', topicId: 13, question: '¿Cuál es el framework del kernel fundamental sobre el que se apoya iptables para engancharse al stack de red?', options: ['BPF', 'Netfilter', 'TCP Wrapper', 'AppArmor'], answer: 1, explanation: 'Netfilter proporciona los "hooks" en el kernel de Linux que permiten a iptables/nftables interceptar y manipular paquetes.' },
  { id: 'lpic2-212-15', topicId: 13, question: '¿Qué comando guarda permanentemente las reglas de iptables en la salida estándar para crear scripts de respaldo en la mayoría de las distribuciones?', options: ['iptables-save', 'iptables-backup', 'iptables -S', 'service iptables save'], answer: 0, explanation: '`iptables-save` vuelca las reglas en un formato legible por máquina (que puede restaurarse con `iptables-restore`).' },
  { id: 'lpic2-212-16', topicId: 13, question: '¿Qué es un Network Vulnerability Test (NVT) en el contexto de OpenVAS/Greenbone?', options: ['Un sniffer de paquetes', 'Un script de plugin que proporciona la lógica para detectar una vulnerabilidad específica en un host remoto', 'Una técnica de escaneo de puertos', 'Una regla de detección de intrusos'], answer: 1, explanation: 'Los NVTs son básicamente los scripts de firma ejecutados por OpenVAS para confirmar si un objetivo es vulnerable.' },
  { id: 'lpic2-212-17', topicId: 13, question: '¿Qué comando vacía (limpia) todas las reglas en la tabla de iptables seleccionada actualmente?', options: ['iptables -X', 'iptables -Z', 'iptables -F', 'iptables -R'], answer: 2, explanation: '`-F` (Flush) borra instantáneamente todas las reglas de todas las cadenas (o de una cadena especificada).' },
];
